<?php declare(strict_types=1);namespace App\Services;final class StreamingHealthService{public function __construct(private SystemMetricsService $system,private StreamMetricsService $stream,private StreamHealthService $health,private ServerProfileService $server){}public function snapshot(?array $active):array{$s=$this->system->collect();$m=$this->stream->collect($active);$h=$this->health->score($s,['encoding_speed'=>$m['speed'],'connected'=>$m['connected']]);return ['server'=>$this->server->profile(),'system'=>$s,'stream'=>$m,'health'=>$h,'recommendation'=>$h['status']==='healthy'?null:'Use a lower profile on next restart.'];}}
